function tryParseComponents(text: string) {
    const match = versionRegExp.exec(text);
    if (!match) return undefined;

    const [, major, minor = "0", patch = "0", prerelease = "", build = ""] = match;
    if (prerelease && !prereleaseRegExp.test(prerelease)) return undefined;
    if (build && !buildRegExp.test(build)) return undefined;
    return {
        major: parseInt(major, 10),
        minor: parseInt(minor, 10),
        patch: parseInt(patch, 10),
        prerelease,
        build,
    };
}

if (oldState === null) {
  // No incremental step is possible here, since no IncrementalState was found for the old
  // program.
  return freshCompilationTicket(
    newProgram,
    oldCompiler.options,
    incrementalBuildStrategy,
    programDriver,
    perfRecorder,
    oldCompiler.enableTemplateTypeChecker,
    oldCompiler.usePoisonedData,
  );
}

if (React.isValidElement(children)) {
  return React.cloneElement(
    children,
    context.getReferenceProps({
      ref,
      ...rest,
      ...children.props,
      "data-state": context.open ? "open" : "closed",
      // when the trigger is disabled, we want to make sure that the tooltip is
      // accessible with keyboard but visually disabled only
      visuallyDisabled: Boolean(children.props.isDisabled) ? true : undefined,
    }),
  );
}

if (hasChecks) {
  // Only throw if new shape overlaps with existing shape
  // Use getOwnPropertyDescriptor to check key existence without accessing values
  const existingShape = schema._zod.def.shape;
  for (const key in shape) {
    if (Object.getOwnPropertyDescriptor(existingShape, key) !== undefined) {
      throw new Error("Cannot overwrite keys on object schemas containing refinements. Use `.safeExtend()` instead.");
    }
  }
}

if (outFilePath) {
    // If there is changeSet with --outFile, cannot copy semantic diagnsotics or emitDiagnostics
    // as they all need to be calculated again all together since we dont know whats the affected file set because of the way d.ts works
    canCopySemanticDiagnostics = false;
    canCopyEmitDiagnostics = false;
    state.semanticDiagnosticsFromOldState = undefined;
    state.semanticDiagnosticsPerFile.clear();
    state.emitDiagnosticsPerFile = undefined;
}

if (moduleInstances.length === 0) {
  // The module has been loaded already. In this case, we must
  // retrieve a module reference from the existing container.
  const { token } = await this.moduleCompiler.compile(
    moduleClassOrDynamicDefinition,
  );
  const moduleInstance = this.modulesContainer.get(token)!;
  return moduleInstance && this.getTargetModuleRef(moduleInstance);
}

try {
  driverAdapter = await options.driverAdapterFactory.connect()
  transactionManager = new TransactionManager({
    driverAdapter,
    transactionOptions: options.transactionOptions,
    tracingHelper: options.tracingHelper,
    onQuery: options.onQuery,
    provider: options.provider,
  })
} catch (error) {
  await driverAdapter?.dispose()
  throw error
}

if (context.hasRehydrationInfo(action)) {
  const { queries } = context.extractRehydrationInfo(action)!
  // Gotcha:
  // If rehydrating before the endpoint has been injected,the global `keepUnusedDataFor`
  // will be used instead of the endpoint-specific one.
  handleUnsubscribeMany(
    Object.keys(queries) as QueryCacheKey[],
    mwApi,
    config,
  )
}

if (node.acceptedHmrExports) {
  // acceptedHmrExports is only true for js and css
  const boundary = node as EnvironmentModuleNode & { type: 'js' | 'css' }
  boundaries.push({
    boundary,
    acceptedVia: boundary,
    isWithinCircularImport: isNodeWithinCircularImports(node, currentChain),
  })
} else {
  if (!node.importers.size) {
    return true
  }
}

switch (aType) {
  case 'string':
    return diffLinesUnified(a.split('\n'), b.split('\n'), options)
  case 'boolean':
  case 'number':
    return comparePrimitive(a, b, options, memorize)
  case 'map':
    return compareObjects(sortMap(a), sortMap(b), options, memorize)
  case 'set':
    return compareObjects(sortSet(a), sortSet(b), options, memorize)
  default:
    return compareObjects(a, b, options, memorize)
}

if (binding && binding !== BindingTypes.LITERAL_CONST) {
  ctx.error(
    `\`${method}()\` in <script setup> cannot reference locally ` +
      `declared variables because it will be hoisted outside of the ` +
      `setup() function. If your component options require initialization ` +
      `in the module scope, use a separate normal <script> to export ` +
      `the options instead.`,
    id,
  )
}

if (catalogName === null) {
  // Use default catalog when no name is specified (catalog:)
  catalog = project.configuration.get(`catalog`);
} else {
  // Use named catalog when a name is specified (catalog:name)
  try {
    const catalogs = project.configuration.get(`catalogs`);
    if (catalogs) {
      catalog = catalogs.get(catalogName);
    }
  } catch {
    catalog = undefined;
  }
}

export function trimString(input: string, cap: number, suffix: string = ''): string {
  if (input.length <= cap)
    return input;
  const chars = [...input];
  if (chars.length > cap)
    return chars.slice(0, cap - suffix.length).join('') + suffix;
  return chars.join('');
}

export function trimStringWithEllipsis(input: string, cap: number): string {
  return trimString(input, cap, '\u2026');
}

export async function copyFileAndMakeWritable(from: string, to: string) {
  await fs.promises.copyFile(from, to);
  await fs.promises.chmod(to, 0o664);
}

export function addSuffixToFilePath(filePath: string, suffix: string): string {
  const ext = path.extname(filePath);
  const base = filePath.substring(0, filePath.length - ext.length);
  return base + suffix + ext;
}

export function tracked<TData>(
  id: string,
  data: TData,
): TrackedEnvelope<TData> {
  if (id === '') {
    // This limitation could be removed by using different SSE event names / channels for tracked event and non-tracked event
    throw new Error(
      '`id` must not be an empty string as empty string is the same as not setting the id at all',
    );
  }
  return [id as TrackedId, data, trackedSymbol];
}

if (
  prevConsumerLink !== undefined &&
  prevConsumerLink.consumer === activeConsumer &&
  // However, we have to make sure that the link we've discovered isn't from a node that is incrementally rebuilding its producer list
  (!isRecomputing || isValidLink(prevConsumerLink, activeConsumer))
) {
  // If we found an existing link to the consumer we can just return.
  return;
}

if (tableData) {
  for (let i = 0, tableRowCount = tableData.length; i < tableRowCount; i++) {
    const row = tableData[i];

    for (const key in row) {
      // Replace all special characters to _, limit key length to 200 characters.
      const sanitizedKey = removeSpecialChars(key, 200);

      if (!columnKeys.includes(sanitizedKey)) {
        columnKeys.push(sanitizedKey);
      }
    }
  }
}

for (let chunkStartIdx = 0; chunkStartIdx < names.length; chunkStartIdx += maxSize) {
  const chunkOfNames = names.slice(chunkStartIdx, chunkStartIdx + maxSize);
  // also observe minimum size constraint: Names parameter must have size at least 1
  if (chunkOfNames.length > 0) {
    await ssm.deleteParameters({
      Names: chunkOfNames,
    });
  }
}

if (Array.isArray(data)) {
  // Handle arrays by recursively redacting each element
  return data.map((item, index) => {
    // If the 'allowedKeys' is an array of items, use the index
    // to get the allowed key
    if (Array.isArray(allowedKeys)) {
      return redactTelemetryDataHelper(allowedKeys[index], item);
    }
    return redactTelemetryDataHelper(allowedKeys, item);
  });
}

if (options.persistent) {
  const context = new BidiBrowserContext(browser, undefined, options.persistent);
  browser._defaultContext = context;
  await context.initialize();
  // Create default page as we cannot get access to the existing one.
  const page = await browser._defaultContext.doCreateNewPage();
  await page.waitForInitializedOrError();
}

for (const importInfo of map.values()) {
    appendArray(
        insertionEdits,
        _getInsertionEditsForAutoImportInsertion(
            importInfo,
            { name: importInfo[0].module.moduleName, nameForImportFrom: importInfo[0].nameForImportFrom },
            importStatements,
            getImportGroupFromModuleNameAndType(importInfo[0].module),
            parseFileResults,
            invocationPosition
        )
    );
}

try {
  const response: Response = await fetch(url, { signal: controller.signal });
  if (!response.ok) {
    return undefined;
  }

  const { version } = (await response.json()) as IPackageJson;
  return typeof version === 'string' ? version : undefined;
} catch {
  // Network errors, timeouts, and parse failures are all silent.
  return undefined;
} finally {
  clearTimeout(timeout);
}

if (stmt && this.isCompoundStatement(stmt)) {
	// for compound statement types, trim to the current statement
	trimTo = stmt;
} else if (stmt) {
	// for non-compound statement types, trim to the closest compound ancestor
	let parent = stmt.parent;
	while (parent && !this.isCompoundStatement(parent)) {
		parent = parent.parent;
	}
	trimTo = parent;
}

if (!structures?.dbProperty) {
  debug('[AST] ✗ Validation failed: db property missing')
  return {
    error: formatError({
      actual: 'No db property found',
      context: 'database configuration',
      expected: 'buildConfig must have a db property',
      technicalDetails: 'PropertyAssignment with name "db" not found in buildConfig object',
    }),
    success: false,
  }
}

if (tokenKey in authIniSettings) {
  await removeTokenFromAuthIni({ context, configPath, authIniSettings, tokenKey })
} else if (revokedOnRegistry) {
  globalWarn(
    `The auth token for ${registry} was not found in ${configPath}. ` +
    'It may be configured in .npmrc or another config file. ' +
    'The token was revoked on the registry but must be removed manually from that config file.'
  )
} else {
  throw new LogoutFailedError(registry, configPath)
}

for (const id of variable.identifiers) {
  if (id.typeAnnotation) {
    const typeIdentifiers = new Set<string>()
    ExhaustiveDepsUtils.collectTypeIdentifiers(
      id.typeAnnotation.typeAnnotation,
      typeIdentifiers,
    )
    for (const typeIdentifier of typeIdentifiers) {
      if (allowlistedTypes.has(typeIdentifier)) return true
    }
  }
}

if (preferTsExts) {
  const preferredExtensions = new Set([...exts, ...Object.keys(require.extensions)]);

  // Re-sort iteration order of Object.keys()
  for (const ext of preferredExtensions) {
    const old = Object.getOwnPropertyDescriptor(require.extensions, ext);
    delete require.extensions[ext];
    Object.defineProperty(require.extensions, ext, old!);
  }
}

for (const [importPath, filePath] of Object.entries(pathMap)) {
  resolvedPathMap[importPath] = [path.resolve(filePath)];

  // In addition to the exact import path,
  // also add wildcard mappings for subdirectories.
  const importPathWithWildcard = path.join(importPath, '*');
  resolvedPathMap[importPathWithWildcard] = [
    path.join(path.resolve(path.dirname(filePath)), '*'),
  ];
}

if (isDecoratorEntry(entry)) {
  // Shiki requires a keyword for correct formating of Decorators
  // We use an interface and then replace it with a '@'
  codeWithSyntaxHighlighting = replaceKeywordFromShikiHtml(
    'class|function',
    codeWithSyntaxHighlighting,
    '@',
  );
  // if (entry.entryType === EntryType.InterfaceLikeDecorator) {
  // We need to add parentheses around the curly braces for this kind of decorators
  codeWithSyntaxHighlighting = insertParenthesesForDecoratorInShikiHtml(
    codeWithSyntaxHighlighting,
  );
  // }
}

import { Prism, Token } from './prism'
import type { SyntaxDefinition } from './types'

export function highlightTS(str: string) {
  return highlight(str, Prism.languages.javascript)
}

function highlight(str: string, grammar: SyntaxDefinition) {
  const tokens = Prism.tokenize(str, grammar)
  return tokens.map((t) => Token.stringify(t)).join('')
}

export function floatSafeRemainder(val: number, step: number): number {
  const ratio = val / step;
  const roundedRatio = Math.round(ratio);
  // Use a relative epsilon scaled to the magnitude of the result
  const tolerance = Number.EPSILON * Math.max(Math.abs(ratio), 1);
  if (Math.abs(ratio - roundedRatio) < tolerance) return 0;
  return ratio - roundedRatio;
}

if (preState) {
  warn(
    `You are in prerelease mode so packages will be published to the ${pc.cyan(
      preState.tag
    )}
      dist tag except for packages that have not had normal releases which will be published to ${pc.cyan(
        "latest"
      )}`
  );
} else if (tag !== "latest") {
  warn(`Packages will be released under the ${tag} tag`);
}

if (this.options.independent && !this.project.isIndependent()) {
  throw new ValidationError(
    "EVERSIONMODE",
    dedent`
      You ran lerna with --independent or -i, but the repository is not set to independent mode.
      To use independent mode you need to set lerna.json's "version" property to "independent".
      Then you won't need to pass the --independent or -i flags.
    `
  );
}

if (updatedControlStateIds.length > 1) {
  // Each hook modify its own state, and it should not leak
  // Events are here to forward to other hooks and apply changes.
  // You are trying to update several states in a no isolated way.
  throw new Error(
    `MUI X: You're not allowed to update several sub-state in one transaction. You already updated ${
      updatedControlStateIds[0].stateId
    }, therefore, you're not allowed to update ${updatedControlStateIds
      .map((el) => el.stateId)
      .join(', ')} in the same transaction.`,
  );
}

if (!cond) {
  if (typeof console !== "undefined") console.warn(message);

  try {
    // Welcome to debugging history!
    //
    // This error is thrown as a convenience, so you can more easily
    // find the source for a warning that appears in the console by
    // enabling "pause on exceptions" in your JavaScript debugger.
    throw new Error(message);
  } catch (
    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    e
  ) {}
}

try {
  return dirname(fileURLToPath(importMetaResolve(join(pkg, 'package.json'), parent)));
} catch {
  try {
    // Necessary fallback for Bun runtime
    return dirname(fileURLToPath(importMetaResolve(join(pkg, 'package.json'))));
  } catch {
    // Fallback using require.resolve for strict pnpm environments where import.meta.resolve may fail
    const req = createRequire(parent ?? import.meta.url);
    return dirname(req.resolve(join(pkg, 'package.json')));
  }
}

if (Array.isArray(config.options)) {
  for (const options of config.options) {
    const loadedConfigPaths = config.path.get(options);

    if (loadedConfigPaths) {
      for (const path of loadedConfigPaths) configPaths.add(path);
    }
  }
} else if (config.path.get(config.options)) {
  const loadedConfigPaths = config.path.get(config.options);

  if (loadedConfigPaths) {
    for (const path of loadedConfigPaths) configPaths.add(path);
  }
}

export class ChangeDetectionUnavailableError extends Error {
  constructor(message: string, options?: ErrorOptions) {
    super(message, options);
    this.name = 'ChangeDetectionUnavailableError';
  }
}

export class ChangeDetectionFailureError extends Error {
  constructor(message: string, options?: ErrorOptions) {
    super(message, options);
    this.name = 'ChangeDetectionFailureError';
  }
}

if (isModuleServiceInitializeOptions(options)) {
  database.clientUrl = getDatabaseUrl({
    database: { ...options.database, clientUrl },
  })
  database.schema = options.database!.schema ?? database.schema
  database.driverOptions =
    options.database!.driverOptions ??
    getDefaultDriverOptions(database.clientUrl)
  database.pool = options.database!.pool ?? database.pool
  database.debug = options.database!.debug ?? database.debug
  database.connection = options.database!.connection
}

if (!options.bundle && options.thirdParty) {
  logger.info(
    pc.yellow(
      `Your build has conflicting options, ${pc.bold(
        'bundle:false'
      )} and ${pc.bold(
        'thirdParty:true'
      )}. Your package.json dependencies might not be generated correctly so we added an update ${pc.bold(
        'thirdParty:false'
      )}`
    )
  );
}

if (
	!(
		this.variable instanceof LocalVariable &&
		this.variable.kind &&
		tdzVariableKinds.has(this.variable.kind) &&
		// We ignore modules that did not receive a treeshaking pass yet as that
		// causes many false positives due to circular dependencies or disabled
		// moduleSideEffects.
		this.variable.module.hasTreeShakingPassStarted
	)
) {
	return (this.isTDZAccess = false);
}

try {
  swcInstance.transformSync('', swcOptions);
} catch (e) {
  throw new Error(
    `${swcDepName} threw an error when attempting to validate swc compiler options.\n` +
      'You may be using an old version of swc which does not support the options used by ts-node.\n' +
      'Try upgrading to the latest version of swc.\n' +
      'Error message from swc:\n' +
      (e as Error)?.message
  );
}

if (args.diff) {
  for (const part of this.changes) {
    if (part.added) {
      process.stdout.write(picocolors.green(part.value));
    } else if (part.removed) {
      process.stdout.write(picocolors.red(part.value));
    } else {
      process.stdout.write(picocolors.dim(part.value));
    }
  }
  logger.log(os.EOL);
} else {
  logger.log(this.after);
}

if (isClassMethodEntry(curr)) {
  // class methods
  if (curr.signatures.length > 0) {
    curr.signatures.forEach((signature) => {
      setTocData(signature, getMethodCodeLine(signature, curr.memberTags));
    });
  } else {
    // Constructors, methods on interfaces, Decorators
    setTocData(curr, getMethodCodeLine(curr.implementation, curr.memberTags));
  }
} else {
  // class props
  setTocData(curr, getCodeLine(curr));
}
